const body = $json.body ?? $json;
const messageRaw = String($json.Message ?? body.message ?? body.text ?? body.pergunta ?? '').trim();
const sessionId = String($json['Chat Id'] ?? body.sessionId ?? body.clienteId ?? 'cliente-anonimo');
return [{
  ...$json,
  body,
  sessionId,
  messageRaw,
  message: messageRaw.toLowerCase(),
  page: body.page ?? '/loja',
  cart: Array.isArray(body.cart) ? body.cart : [],
  receivedAt: new Date().toISOString()
}];

return [{
  ...$json,
  context: {
    loja: 'JB Motos',
    tom: 'Atendimento claro, direto, educado e comercial',
    regras: [
      'Nunca prometer pagamento real enquanto Mercado Pago nao estiver conectado',
      'Confirmar antes de adicionar servico ao carrinho',
      'Quando confirmar carrinho, retornar action add_to_cart e cart_animation',
      'Quando for duvida de pagamento, explicar que por enquanto e simulacao'
    ],
    rotas: {
      loja: '/loja',
      ofertas: '/loja#ofertas',
      servicos: '/loja#servicos',
      carrinho: '/loja/carrinho',
      conta: '/loja/minha-conta'
    }
  }
}];

const editFields = $('Edit Fields').first().json ?? {};
const body = $json.body ?? editFields.body ?? $json;
const messageRaw = String($json.Message ?? editFields.Message ?? body.message ?? body.text ?? body.pergunta ?? '').trim();
const message = messageRaw.toLowerCase();
const sessionId = String($json['Chat Id'] ?? editFields['Chat Id'] ?? body.sessionId ?? body.clienteId ?? 'cliente-anonimo');
const langchainOutput = String($json.output ?? '').trim();
let langchainDecision = {};
try {
  langchainDecision = langchainOutput ? JSON.parse(langchainOutput) : {};
} catch (error) {
  langchainDecision = { replySuggestion: langchainOutput };
}
const aiIntent = langchainDecision.intent ?? $json.ai?.decision?.intent ?? '';
const aiEntities = langchainDecision.entities ?? $json.ai?.decision?.entities ?? {};

const catalogo = {
  ofertas: [
    { id: 'oferta-oleo-10w30', nome: 'Óleo Motor 10W30', preco: 48.9, categoria: 'Lubrificantes' },
    { id: 'oferta-capacete-pro-tork', nome: 'Capacete Pro Tork', preco: 249.9, categoria: 'Acessórios' },
    { id: 'oferta-pastilha-freio', nome: 'Pastilha de Freio', preco: 35, categoria: 'Freios' }
  ],
  cartazes: [
    { id: 'cartaz-revisao', titulo: 'Revisão preventiva', rota: '/loja#servicos' },
    { id: 'cartaz-promocoes', titulo: 'Promoções da semana', rota: '/loja#ofertas' }
  ],
  servicos: [
    { id: 'serv-troca-oleo', nome: 'Troca de óleo', preco: 35, pecaSugerida: 'Óleo Motor 10W30', pecaPreco: 48.9 },
    { id: 'serv-pastilha-freio', nome: 'Troca de pastilha de freio', preco: 60, pecaSugerida: 'Pastilha de Freio', pecaPreco: 35 },
    { id: 'serv-relacao', nome: 'Troca de relação', preco: 90, pecaSugerida: 'Kit Relação CG 160', pecaPreco: 142.5 },
    { id: 'serv-pneu', nome: 'Troca de pneu', preco: 45, pecaSugerida: 'Pneu Traseiro 90/90', pecaPreco: 189.9 }
  ]
};

function moeda(valor) {
  return valor.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
}

function detectarServico() {
  const termoIa = String(aiEntities.servico ?? '').toLowerCase();
  return catalogo.servicos.find((servico) => {
    const nome = servico.nome.toLowerCase();
    return nome.includes(termoIa) || termoIa.includes(nome) || message.includes(nome) || nome.split(' ').some((parte) => parte.length > 3 && message.includes(parte));
  });
}

function respostaBase(intent, reply, extra = {}) {
  return {
    ok: true,
    assistant: 'cliente',
    sessionId,
    intent,
    reply,
    quickReplies: extra.quickReplies ?? ['Ver ofertas', 'Ver serviços', 'Formas de pagamento', 'Ir para carrinho'],
    actions: extra.actions ?? [],
    data: { ...(extra.data ?? {}), ia: { provider: 'n8n_langchain', output: langchainOutput, decision: langchainDecision } }
  };
}

if (!message) {
  return [respostaBase('boas_vindas', 'Olá! Sou o assistente da JB Motos. Posso te ajudar com ofertas, serviços, formas de pagamento ou levar itens para o carrinho.', {
    quickReplies: ['Ofertas', 'Cartazes', 'Serviços', 'Formas de pagamento']
  })];
}

if (aiIntent === 'pagamento' || message.includes('pagamento') || message.includes('pagar') || message.includes('pix') || message.includes('cartao') || message.includes('cartão')) {
  return [respostaBase('pagamento', 'Hoje trabalhamos com simulação de pagamento para testes: PIX, cartão, dinheiro e pagamento no balcão. Quando o Mercado Pago for conectado, essa etapa vai abrir o checkout real.', {
    actions: [{ type: 'navigate', payload: { route: '/loja/minha-conta' } }]
  })];
}

if (aiIntent === 'ofertas_cartazes' || message.includes('oferta') || message.includes('promo') || message.includes('cartaz')) {
  return [respostaBase('ofertas_cartazes', 'Encontrei ofertas e cartazes ativos. Vou te direcionar para a área correta da loja.', {
    data: { ofertas: catalogo.ofertas, cartazes: catalogo.cartazes },
    actions: [{ type: 'navigate', payload: { route: '/loja#ofertas' } }],
    quickReplies: catalogo.ofertas.map((item) => item.nome)
  })];
}

if (['lista_servicos', 'confirmar_servico', 'servico_confirmado'].includes(aiIntent) || message.includes('serviço') || message.includes('servico') || message.includes('revisao') || message.includes('revisão') || detectarServico()) {
  const servico = detectarServico();
  if (!servico) {
    return [respostaBase('lista_servicos', 'Temos estes serviços disponíveis. Escolha um para eu te mostrar peça sugerida e valor.', {
      data: { servicos: catalogo.servicos },
      quickReplies: catalogo.servicos.map((item) => item.nome)
    })];
  }

  const confirmou = Boolean(aiEntities.confirmou) || ['confirmo', 'quero', 'adicionar', 'pode colocar', 'fechar'].some((termo) => message.includes(termo));
  const itemCarrinho = {
    id: servico.id,
    nome: servico.nome,
    tipo: 'servico',
    precoServico: servico.preco,
    peca: servico.pecaSugerida,
    precoPeca: servico.pecaPreco,
    total: servico.preco + servico.pecaPreco
  };

  if (confirmou) {
    return [respostaBase('servico_confirmado', `Perfeito. Adicionei ${servico.nome} ao carrinho. Serviço: ${moeda(servico.preco)} + peça sugerida (${servico.pecaSugerida}): ${moeda(servico.pecaPreco)}. Total: ${moeda(itemCarrinho.total)}.`, {
      data: { itemCarrinho },
      actions: [
        { type: 'add_to_cart', payload: itemCarrinho },
        { type: 'cart_animation', payload: { increment: 1, target: 'cart-icon' } },
        {
          type: 'create_service_request',
          payload: {
            clienteNome: 'Cliente da loja',
            clienteId: sessionId,
            servicoNaMoto: servico.nome,
            descricao: `Solicitação criada pelo assistente: ${servico.nome}. Peça sugerida: ${servico.pecaSugerida}.`,
            valorServico: moeda(servico.preco),
            observacao: `Peça sugerida: ${servico.pecaSugerida} (${moeda(servico.pecaPreco)})`,
            tipo: 'servico',
            status: 'pendente',
            origem: 'loja_online'
          }
        }
      ],
      quickReplies: ['Ir para carrinho', 'Ver mais serviços', 'Continuar comprando']
    })];
  }

  return [respostaBase('confirmar_servico', `Você escolheu ${servico.nome}. Para esse serviço, sugerimos a peça ${servico.pecaSugerida}. Serviço: ${moeda(servico.preco)} + peça: ${moeda(servico.pecaPreco)}. Deseja adicionar ao carrinho?`, {
    data: { itemCarrinho },
    quickReplies: [`Confirmo ${servico.nome}`, 'Ver outros serviços', 'Cancelar']
  })];
}

if (aiIntent === 'carrinho' || message.includes('carrinho') || message.includes('finalizar') || message.includes('checkout')) {
  return [respostaBase('carrinho', 'Certo. Vou abrir o carrinho para você revisar os itens e finalizar a compra.', {
    actions: [{ type: 'navigate', payload: { route: '/loja/carrinho' } }]
  })];
}

return [respostaBase('fallback', langchainDecision.replySuggestion || langchainDecision.replySuggestion || $json.ai?.decision?.replySuggestion || 'Posso te ajudar com ofertas, cartazes, serviços, formas de pagamento ou carrinho. O que você deseja fazer agora?', {
  quickReplies: ['Ver ofertas', 'Ver serviços', 'Formas de pagamento', 'Carrinho']
})];

return [{
  ...$json,
  audit: {
    workflow: 'Assistente.Cliente',
    version: 'cliente-profissional-v2',
    timestamp: new Date().toISOString(),
    intent: $json.intent,
    sessionId: $json.sessionId,
    actionsCount: Array.isArray($json.actions) ? $json.actions.length : 0
  }
}];
